import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"玛雷家行刑剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/玛雷家行刑剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/玛雷家行刑剑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/2.C级/玛雷家行刑剑.md"};function _(l,a,p,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"玛雷家行刑剑",tabindex:"-1"},[s("玛雷家行刑剑 "),e("a",{class:"header-anchor",href:"#玛雷家行刑剑","aria-label":'Permalink to "玛雷家行刑剑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="玛雷家行刑剑-1" tabindex="-1">玛雷家行刑剑 <a class="header-anchor" href="#玛雷家行刑剑-1" aria-label="Permalink to &quot;玛雷家行刑剑&quot;">​</a></h1><p>玛雷家行刑剑<br> C+1000<br> 魔幻本质<br> 分类/专业：重剑<br> 武器伤害：12L<br> 日荫城的城主，同为行刑者一族——玛雷家的宝剑。<br> “传说中的武器”之一。<br> 以铃珠猎人身份受令人畏惧的“荆棘”艾隆梅尔，在行刑场抢走此剑，作为自己的武器，并将故乡欧赫的战技赋予其上。<br> 描述：不知何种材料的剑柄以被暗红色浸透，布满荆棘的剑格延伸出布满陈旧血迹宽大的剑身，其并不如其他剑一般具有锋利尖端，而是变为更适合劈砍的圆刃，对应其行刑剑的名号。<br> 该剑可以使用魔力、斗气、法力等西方能量池驱动。</p><p>自由动作消耗6点能量启动持续一轮，剑身将满布血色，随着你的心意在空中飞舞，在这一状态下，人物可以操纵玛雷家行刑剑对15米距离内直线中的所有敌人发动攻击，剑身血红光芒大盛后急速飞向攻击目标。</p><p>专用战技：欧赫剑舞<br> 整轮动作使用，将6点能量灌入剑中，旋转之后向前方进行冲锋，并释放的战技。<br> 整把剑会剧烈的旋转并散发出血腥的红光，这次冲锋会将路径上所有敌人均作为攻击目标，并视为【接触攻击】。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
